function StructPlayerInfo:CreateByPb(pb)
    self._playerId = pb.playerId
    self._power = pb.power
    self._grade = pb.grade
    self._head=pb.head
    self._name = pb.name
    self._vipLevel = pb.vipLevel
    self._figure = pb.figure
    self._like = pb.like
    self._score = pb.score
    self._rank = pb.rank
    self._battleNum = pb.battleNum
    self._guildId = pb.guildId
    self._oldRank =pb.oldRank
    self._change = pb.change
    self._guildName =pb.guildName
    self._headFrame=pb.headFrame
    self._province=pb.province
    self._city=pb.city
    self._serverId=pb.serverId
    self._serverName=pb.serverName
    self._playerState=pb.playerState
    self._lastLogoutTime=pb.lastLogoutTime
	self._ladderPower = pb.ladderPower or 0
    self.sex = pb.sex or 0
    if pb.badge then
        self.badge = {}
        for i, v in ipairs(pb.badge) do
           local arr = string.split(v,"=")
            self.badge[tonumber(arr[2])] = tonumber(arr[1])
        end
    end

    self.signature = pb.signature or ""
    self.title = pb.title
    self.age = pb.age or 1
    self.disallowTalk = pb.disallowTalk
	self._spaceName = pb.spaceName or ""
    local tag = pb.tag
    local tags = {}
    if tag then
        for i, v in ipairs(tag) do
            local arr = string.split(v,"=")
            tags[tonumber(arr[2])] = tonumber(arr[1])
        end
    end
    self.tag = tags
    self.backGround = pb.backGround
    self.ip = pb.ip
    self.ipCountry = pb.ipCountry
    self.ipProvince = pb.ipProvince
    self.shieldInfo = pb.shieldInfo
    self.robot = pb.robot
end

